    overflow-y: auto;
}

.channel-item {
    padding: 0.3rem 0.5rem;
    border-radius: 4px;
}

.channel-item:hover {
    background: #f8f9fa;
}

/* ── Expandable panel ── */
.expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 6px;
    overflow: hidden;
}

.expandable-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    width: 100%;
    padding: 0.85rem 1rem;
    border: none;
    background: #fff;
    cursor: pointer;
    font-size: 0.95rem;
    transition: background 0.15s;
}

.expandable-header:hover {
    background: #f8f9fa;
}

.expand-icon {
    color: #6c757d;
    font-size: 0.8rem;
}

.expandable-body {
    padding: 1rem;
    border-top: 1px solid #e9ecef;
    background: #fdfdfe;
}

/* ── Appearance preview card ── */
.preview-card {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1.5rem;
    background: #fff;
    color: #212529;
    transition: all 0.3s ease;
    font-size: 0.95rem;
}

.preview-label {
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #6c757d;
    margin-bottom: 0.75rem;
    font-weight: 600;
}

.preview-header {
    font-size: 1.25rem;
    font-weight: 600;
    margin-bottom: 0.5rem;
}

.preview-text {
    margin-bottom: 0.5rem;
    line-height: 1.5;
}

.preview-meta {
    font-size: 0.8rem;
    color: #6c757d;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-dark .preview-label,
.preview-dark .preview-meta {
    color: #999;
}

.preview-small {
    font-size: 0.82rem;
}

.preview-small .preview-header {
    font-size: 1.05rem;
}

.preview-large {
    font-size: 1.1rem;
}

.preview-large .preview-header {
    font-size: 1.45rem;
}

.preview-compact {
    padding: 0.75rem;
    line-height: 1.25;
}

.preview-compact .preview-header {
    margin-bottom: 0.25rem;
}

.preview-compact .preview-text {
    margin-bottom: 0.25rem;
}

/* ── Responsive ── */
@media (max-width: 768px) {
    .settings-container {
        flex-direction: column;
    }

    .settings-sidebar {
        width: 100%;
        min-width: unset;
        flex-direction: row;
        flex-wrap: wrap;
        padding: 0.5rem;
        border-right: none;
        border-bottom: 1px solid #e9ecef;
    }

    .sidebar-title {
        display: none;
    }

    .sidebar-item {
        padding: 0.5rem 0.75rem;
        font-size: 0.85rem;
    }

    .sidebar-item.active {
        border-left: none;
        border-bottom: 2px solid #0d6efd;
        padding-left: 0.75rem;
    }

    .settings-content {
        padding: 1rem;
    }
}

toolCalls.args:
{"file_text": "@page "/settings"
@using sv_b24ac199976444b6a323d33841cb0e8b.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-container">
    <!-- Left sidebar navigation -->
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        @foreach (var section in _sections)
        {
            <button class="sidebar-item @(section == _activeSection ? "active" : "")"
                    @onclick="() => SetActiveSection(section)">
                <span class="sidebar-icon">@GetSectionIcon(section)</span>
                @section
            </button>
        }
    </nav>

    <!-- Main content area -->
    <div class="settings-content">
        @if (_loading)
        {
            <div class="text-center p-5">
                <div class="spinner-border" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            <!-- Toast notification -->
            @if (_showToast)
            {
                <div class="settings-toast @(_toastType)" role="alert">
                    <span>@_toastMessage</span>
                    <button class="btn-close btn-close-sm" @onclick="() => _showToast = false"></button>
                </div>
            }

            @switch (_activeSection)
            {
                case "Profile":
                    @RenderProfileSection()
                    break;
                case "Notifications":
                    @RenderNotificationsSection()
                    break;
                case "Security":
                    @RenderSecuritySection()
                    break;
                case "Appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }
    </div>
</div>

@* ── Profile Section ── *@
@{
    RenderFragment RenderProfileSection() =>
        @<div class="settings-section">
            <h4 class="section-title">Profile</h4>
            <p class="section-description">Manage your public profile information.</p>

            <div class="avatar-area mb-4">
                <img src="@_editProfile!.AvatarUrl" alt="Avatar" class="avatar-preview" />
                <div class="avatar-info">
                    <span class="text-muted small">Avatar URL</span>
                    <code class="d-block text-truncate" style="max-width:320px;">@_editProfile.AvatarUrl</code>
                </div>
            </div>

            <div class="mb-3">
                <label class="form-label">Display Name</label>
                <input type="text" class="form-control" @bind="_editProfile.DisplayName" />
            </div>
            <div class="mb-3">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" @bind="_editProfile.Email" />
            </div>
            <div class="mb-3">
                <label class="form-label">Bio</label>
                <textarea class="form-control" rows="4" @bind="_editProfile.Bio"></textarea>
            </div>

            <div class="d-flex gap-2">
                <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_saving">
                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Changes
                </button>
                <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges">
                    Discard Changes
                </button>
            </div>
        </div>;
}

@* ── Notifications Section ── *@
@{
    RenderFragment RenderNotificationsSection() =>
        @<div class="settings-section">
            <h4 class="section-title">Notifications</h4>
            <p class="section-description">Choose how you want to be notified.</p>

            <div class="toggle-group">
                <div class="toggle-row">
                    <div>
                        <strong>Email Notifications</strong>
                        <div class="text-muted small">Receive notifications via email</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@_editNotifications!.EmailNotifications"
                               @onchange="e => _editNotifications.EmailNotifications = (bool)e.Value!" />
                    </div>
                </div>
                <div class="toggle-row">
                    <div>
                        <strong>Push Notifications</strong>
                        <div class="text-muted small">Receive push notifications on your devices</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@_editNotifications.PushNotifications"
                               @onchange="e => _editNotifications.PushNotifications = (bool)e.Value!" />
                    </div>
                </div>
                <div class="toggle-row">
                    <div>
                        <strong>Weekly Digest</strong>
                        <div class="text-muted small">Get a weekly summary of activity</div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               checked="@_editNotifications.WeeklyDigest"
                               @onchange="e => _editNotifications.WeeklyDigest = (bool)e.Value!" />
                    </div>
                </div>
            </div>

            <h6 class="mt-4 mb-3">Muted Channels</h6>
            <div class="channel-list">
                @foreach (var channel in _editNotifications.AllChannels)
                {
                    <div class="channel-item">
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                                   checked="@_editNotifications.MutedSet.Contains(channel)"
                                   @onchange="e => ToggleMutedChannel(channel, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"ch-{channel}")">
                                #@channel
                                @if (_editNotifications.MutedSet.Contains(channel))
                                {
                                    <span class="badge bg-secondary ms-1">Muted</span>
                                }
                            </label>
                        </div>
                    </div>
                }
            </div>

            <button class="btn btn-primary mt-4" @onclick="SaveNotifications" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save Preferences
            </button>
        </div>;
}

@* ── Security Section ── *@
@{
    RenderFragment RenderSecuritySection() =>
        @<div class="settings-section">
            <h4 class="section-title">Security</h4>
            <p class="section-description">Manage your account security and active sessions.</p>

            <!-- Change Password expandable panel -->
            <div class="expandable-panel mb-4">
                <button class="expandable-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <span>
                        <strong>Change Password</strong>
                        @if (_security?.LastPasswordChange != null)
                        {
                            <span class="text-muted small ms-2">
                                Last changed @FormatTimeAgo(_security.LastPasswordChange.Value)
                            </span>
                        }
                    </span>
                    <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
                </button>
                @if (_passwordPanelOpen)
                {
                    <div class="expandable-body">
                        <div class="mb-3">
                            <label class="form-label">Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">New Password</label>
                            <input type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Confirm New Password</label>
                            <input type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        <button class="btn btn-warning" @onclick="ChangePassword" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Update Password
                        </button>
                    </div>
                }
            </div>

            <!-- Two-Factor Authentication -->
            <div class="toggle-row mb-4">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <div class="small">
                        @if (_security!.TwoFactorEnabled)
                        {
                            <span class="badge bg-success">Enabled</span>
                        }
                        else
                        {
                            <span class="badge bg-warning text-dark">Disabled</span>
                        }
                    </div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_security.TwoFactorEnabled" disabled />
                </div>
            </div>

            <!-- Active Sessions -->
            <h6 class="mb-3">Active Sessions</h6>
            <div class="table-responsive">
                <table class="table table-hover align-middle">
                    <thead class="table-light">
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in _security.Sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@FormatTimeAgo(session.LastActive)</td>
                                <td class="text-end">
                                    @if (session.Id != _currentSessionId)
                                    {
                                        @if (_confirmRevokeId == session.Id)
                                        {
                                            <span class="me-2 small text-danger">Revoke this session?</span>
                                            <button class="btn btn-danger btn-sm me-1" @onclick="() => RevokeSession(session.Id)">
                                                Yes
                                            </button>
                                            <button class="btn btn-outline-secondary btn-sm" @onclick="() => _confirmRevokeId = null">
                                                No
                                            </button>
                                        }
                                        else
                                        {
                                            <button class="btn btn-outline-danger btn-sm" @onclick="() => _confirmRevokeId = session.Id">
                                                Revoke
                                            </button>
                                        }
                                    }
                                    else
                                    {
                                        <span class="badge bg-info">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>;
}

@* ── Appearance Section ── *@
@{
    RenderFragment RenderAppearanceSection() =>
        @<div class="settings-section">
            <h4 class="section-title">Appearance</h4>
            <p class="section-description">Customize the look and feel of the application.</p>

            <div class="row">
                <div class="col-lg-7">
                    <!-- Theme -->
                    <div class="mb-4">
                        <label class="form-label fw-bold">Theme</label>
                        <div class="d-flex gap-3">
                            @foreach (var theme in new[] { "Light", "Dark", "System" })
                            {
                                <div class="form-check">
                                    <input class="form-check-input" type="radio" name="theme"
                                           id="@($"theme-{theme}")" value="@theme"
                                           checked="@(_editAppearance!.Theme == theme)"
                                           @onchange="() => _editAppearance.Theme = theme" />
                                    <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                                </div>
                            }
                        </div>
                    </div>

                    <!-- Font Size -->
                    <div class="mb-4">
                        <label class="form-label fw-bold">Font Size</label>
                        <div class="d-flex gap-3">
                            @foreach (var size in new[] { "Small", "Medium", "Large" })
                            {
                                <div class="form-check">
                                    <input class="form-check-input" type="radio" name="fontSize"
                                           id="@($"fs-{size}")" value="@size"
                                           checked="@(_editAppearance.FontSize == size)"
                                           @onchange="() => _editAppearance.FontSize = size" />
                                    <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                                </div>
                            }
                        </div>
                    </div>

                    <!-- Language -->
                    <div class="mb-4">
                        <label class="form-label fw-bold">Language</label>
                        <select class="form-select" style="max-width:250px;"
                                value="@_editAppearance.Language"
                                @onchange="e => _editAppearance.Language = e.Value!.ToString()!">
                            @foreach (var lang in _languages)
                            {
                                <option value="@lang">@lang</option>
                            }
                        </select>
                    </div>

                    <!-- Compact Mode -->
                    <div class="toggle-row mb-4">
                        <div>
                            <strong>Compact Mode</strong>
                            <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
                        </div>
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" role="switch"
                                   checked="@_editAppearance.CompactMode"
                                   @onchange="e => _editAppearance.CompactMode = (bool)e.Value!" />
                        </div>
                    </div>

                    <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Save
                    </button>
                </div>

                <!-- Live Preview -->
                <div class="col-lg-5">
                    <div class="preview-card @GetPreviewClasses()">
                        <div class="preview-label">Live Preview</div>
                        <div class="preview-header">Dashboard</div>
                        <p class="preview-text">
                            This is how your content will look with the selected appearance settings.
                        </p>
                        <div class="preview-meta">
                            Theme: @_editAppearance.Theme · Font: @_editAppearance.FontSize · @_editAppearance.Language
                        </div>
                        <div class="d-flex gap-2 mt-2">
                            <span class="badge bg-primary">Tag</span>
                            <span class="badge bg-secondary">Label</span>
                        </div>
                        @if (_editAppearance.CompactMode)
                        {
                            <div class="preview-meta mt-1">✓ Compact mode active</div>
                        }
                    </div>
                </div>
            </div>
        </div>;
}

@code {
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];
    private string _activeSection = "Profile";
    private bool _loading = true;
    private bool _saving;

    // Toast
    private bool _showToast;
    private string _toastMessage = "";
    private string _toastType = "success";

    // Profile
    private ProfileEdit? _editProfile;
    private UserProfile? _savedProfile;

    // Notifications
    private NotificationEdit? _editNotifications;

    // Security
    private SecuritySettings? _security;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _confirmRevokeId;
    private readonly string _currentSessionId = "sess-1";

    // Appearance
    private AppearanceEdit? _editAppearance;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllData();
        _loading = false;
    }

    private async Task LoadAllData()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var secTask = SettingsService.GetSecuritySettingsAsync();
        var appTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, secTask, appTask);

        _savedProfile = await profileTask;
        _editProfile = new ProfileEdit(_savedProfile);
        _editNotifications = new NotificationEdit(await notifTask);
        _security = await secTask;
        _editAppearance = new AppearanceEdit(await appTask);
    }

    private void SetActiveSection(string section)
    {
        _activeSection = section;
        _showToast = false;
        _confirmRevokeId = null;
    }

    private async Task SaveProfile()
    {
        _saving = true;
        var profile = new UserProfile(_editProfile!.DisplayName, _editProfile.Email, _editProfile.AvatarUrl, _editProfile.Bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        _saving = false;
        ShowToast("Profile saved successfully!", "success");
    }

    private void DiscardProfileChanges()
    {
        _editProfile = new ProfileEdit(_savedProfile!);
        ShowToast("Changes discarded.", "info");
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        var prefs = new NotificationPrefs(
            _editNotifications!.EmailNotifications,
            _editNotifications.PushNotifications,
            _editNotifications.WeeklyDigest,
            _editNotifications.MutedSet.ToList()
        );
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        ShowToast("Notification preferences saved!", "success");
    }

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted)
            _editNotifications!.MutedSet.Add(channel);
        else
            _editNotifications!.MutedSet.Remove(channel);
    }

    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            ShowToast("Please fill in all password fields.", "danger");
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            ShowToast("New passwords do not match.", "danger");
            return;
        }

        _saving = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _passwordPanelOpen = false;
        _saving = false;
        ShowToast("Password updated successfully!", "success");
    }

    private async Task RevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _confirmRevokeId = null;
        ShowToast("Session revoked.", "success");
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        var settings = new AppearanceSettings(
            _editAppearance!.Theme,
            _editAppearance.FontSize,
            _editAppearance.Language,
            _editAppearance.CompactMode
        );
        await SettingsService.SaveAppearanceAsync(settings);
        _saving = false;
        ShowToast("Appearance settings saved!", "success");
    }

    private void ShowToast(string message, string type)
    {
        _toastMessage = message;
        _toastType = type;
        _showToast = true;
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        if (_editAppearance!.Theme == "Dark") classes.Add("preview-dark");
        if (_editAppearance.FontSize == "Small") classes.Add("preview-small");
        if (_editAppearance.FontSize == "Large") classes.Add("preview-large");
        if (_editAppearance.CompactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private static string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };

    private static string FormatTimeAgo(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    // Mutable wrapper classes for two-way binding
    private class ProfileEdit
    {
        public string DisplayName { get; set; }
        public string Email { get; set; }
        public string AvatarUrl { get; set; }
        public string Bio { get; set; }

        public ProfileEdit(UserProfile p)
        {
            DisplayName = p.DisplayName;
            Email = p.Email;
            AvatarUrl = p.AvatarUrl;
            Bio = p.Bio;
        }
    }

    private class NotificationEdit
    {
        public bool EmailNotifications { get; set; }
        public bool PushNotifications { get; set; }
        public bool WeeklyDigest { get; set; }
        public HashSet<string> MutedSet { get; set; }
        public List<string> AllChannels { get; set; }

        public NotificationEdit(NotificationPrefs p)
        {
            EmailNotifications = p.EmailNotifications;
            PushNotifications = p.PushNotifications;
            WeeklyDigest = p.WeeklyDigest;
            MutedSet = new HashSet<string>(p.MutedChannels);
            AllChannels = new List<string>(p.MutedChannels);
        }
    }

    private class AppearanceEdit
    {
        public string Theme { get; set; }
        public string FontSize { get; set; }
        public string Language { get; set; }
        public bool CompactMode { get; set; }

        public AppearanceEdit(AppearanceSettings s)
        {
            Theme = s.Theme;
            FontSize = s.FontSize;
            Language = s.Language;
            CompactMode = s.CompactMode;
        }
    }
}
