{"file_text": "/* ── Layout ── */
.settings-container {
    display: flex;
    min-height: calc(100vh - 120px);
    gap: 0;
    background: #f8f9fa;
    border-radius: 8px;
    overflow: hidden;
    box-shadow: 0 1px 3px rgba(0,0,0,.08);
}

/* ── Sidebar ── */
.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #fff;
    border-right: 1px solid #e9ecef;
    padding: 1.25rem 0;
    display: flex;
    flex-direction: column;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    border-bottom: 1px solid #e9ecef;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.7rem 1.25rem;
    border: none;
    background: none;
    text-align: left;
    font-size: 0.925rem;
    color: #495057;
    cursor: pointer;
    transition: background 0.15s, color 0.15s;
    width: 100%;
}

.sidebar-item:hover {
    background: #f1f3f5;
    color: #212529;
}

.sidebar-item.active {
    background: #e7f1ff;
    color: #0d6efd;
    font-weight: 600;
    border-left: 3px solid #0d6efd;
    padding-left: calc(1.25rem - 3px);
}

.sidebar-icon {
    font-size: 1.1rem;
}

/* ── Content area ── */
.settings-content {
    flex: 1;
    padding: 2rem;
    position: relative;
    overflow-y: auto;
}

.settings-section {
    max-width: 800px;
}

.section-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.section-description {
    color: #6c757d;
    margin-bottom: 1.5rem;
}

/* ── Toast ── */
.settings-toast {
    position: sticky;
    top: 0;
    z-index: 10;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 1rem;
    border-radius: 6px;
    margin-bottom: 1.25rem;
    font-size: 0.9rem;
    animation: slideDown 0.25s ease;
}

.settings-toast.success {
    background: #d1e7dd;
    color: #0a3622;
    border: 1px solid #a3cfbb;
}

.settings-toast.danger {
    background: #f8d7da;
    color: #58151c;
    border: 1px solid #f1aeb5;
}

.settings-toast.info {
    background: #cff4fc;
    color: #055160;
    border: 1px solid #9eeaf9;
}

@keyframes slideDown {
    from { opacity: 0; transform: translateY(-10px); }
    to   { opacity: 1; transform: translateY(0); }
}

/* ── Avatar ── */
.avatar-area {
    display: flex;
    align-items: center;
    gap: 1rem;
}

.avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #dee2e6;
}

/* ── Toggle rows ── */
.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0;
}

.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.85rem 0;
    border-bottom: 1px solid #e9ecef;
}

.toggle-row:last-child {
    border-bottom: none;
}

/* ── Channel list ── */
.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    padding: 0.75rem;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    max-height: 220px;
    overflow-y: auto;
}

.channel-item {
    padding: 0.3rem 0.5rem;
    border-radius: 4px;
}

.channel-item:hover {
    background: #f8f9fa;
}

/* ── Expandable panel ── */
.expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 6px;
    overflow: hidden;
}

.expandable-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    width: 100%;
    padding: 0.85rem 1rem;
    border: none;
    background: #fff;
    cursor: pointer;
    font-size: 0.95rem;
    transition: background 0.15s;
}

.expandable-header:hover {
    background: #f8f9fa;
}

.expand-icon {
    color: #6c757d;
    font-size: 0.8rem;
}

.expandable-body {
    padding: 1rem;
    border-top: 1px solid #e9ecef;
    background: #fdfdfe;
}

/* ── Appearance preview card ── */
.preview-card {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1.5rem;
    background: #fff;
    color: #212529;
    transition: all 0.3s ease;
    font-size: 0.95rem;
}

.preview-label {
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: #6c757d;
    margin-bottom: 0.75rem;
    font-weight: 600;
}

.preview-header {
    font-size: 1.25rem;
    font-weight: 600;
    margin-bottom: 0.5rem;
}

.preview-text {
    margin-bottom: 0.5rem;
    line-height: 1.5;
}

.preview-meta {
    font-size: 0.8rem;
    color: #6c757d;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-dark .preview-label,
.preview-dark .preview-meta {
    color: #999;
}

.preview-small {
    font-size: 0.82rem;
}

.preview-small .preview-header {
    font-size: 1.05rem;
}

.preview-large {
    font-size: 1.1rem;
}

.preview-large .preview-header {
    font-size: 1.45rem;
}

.preview-compact {
    padding: 0.75rem;
    line-height: 1.25;
}

.preview-compact .preview-header {
    margin-bottom: 0.25rem;
}

.preview-compact .preview-text {
    margin-bottom: 0.25rem;
}

/* ── Responsive ── */
@media (max-width: 768px) {
    .settings-container {
        flex-direction: column;
    }

    .settings-sidebar {
        width: 100%;
        min-width: unset;
        flex-direction: row;
        flex-wrap: wrap;
        padding: 0.5rem;
        border-right: none;
        border-bottom: 1px solid #e9ecef;
    }

    .sidebar-title {
        display: none;
    }

    .sidebar-item {
        padding: 0.5rem 0.75rem;
        font-size: 0.85rem;
    }

    .sidebar-item.active {
        border-left: none;
        border-bottom: 2px solid #0d6efd;
        padding-left: 0.75rem;
    }

    .settings-content {
        padding: 1rem;
    }
}
